# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.95;

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int N, M;
    std::vector<std::vector<int>> stacks; // stacks[i] = bottom to top, 0-indexed box values
    std::vector<std::pair<int,int>> box_pos; // box_pos[v] = {stack_idx, height_idx}
    long long energy;
    std::vector<std::pair<int,int>> ops; // recorded operations (1-indexed for output)
    int ops_count;

    State() : N(0), M(0), energy(0), ops_count(0) {}

    State(int n, int m, const std::vector<std::vector<int>>& init_stacks)
        : N(n), M(m), energy(0), ops_count(0) {
        stacks.resize(M);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            stacks[i].reserve(N);
            for (int j = 0; j < (int)init_stacks[i].size(); j++) {
                int v = init_stacks[i][j] - 1; // convert to 0-indexed
                stacks[i].push_back(v);
                box_pos[v] = {i, j};
            }
        }
        ops.reserve(N * 3);
    }

    // Move box v (0-indexed) and everything above it to dest stack
    void move(int v, int dest) {
        int src = box_pos[v].first;
        int h = box_pos[v].second;
        int num_moved = (int)stacks[src].size() - h;

        int old_dest_h = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int bv = stacks[src][i];
            box_pos[bv] = {dest, old_dest_h + (i - h)};
            stacks[dest].push_back(bv);
        }
        stacks[src].resize(h);

        energy += num_moved + 1;
        ops.push_back({v + 1, dest + 1});
        ops_count++;
    }

    // Carry out box v (must be on top of its stack)
    void carry_out(int v) {
        int src = box_pos[v].first;
        stacks[src].pop_back();
        ops.push_back({v + 1, 0});
        ops_count++;
    }

    bool is_on_top(int v) const {
        int src = box_pos[v].first;
        int h = box_pos[v].second;
        return h == (int)stacks[src].size() - 1;
    }

    int stack_height(int si) const { return (int)stacks[si].size(); }

    // Get boxes above v (from directly above v to top), in bottom-to-top order
    std::vector<int> get_above(int v) const {
        int src = box_pos[v].first;
        int h = box_pos[v].second;
        std::vector<int> result;
        for (int i = h + 1; i < (int)stacks[src].size(); i++) {
            result.push_back(stacks[src][i]);
        }
        return result;
    }
};

// Evaluate how good a destination is for a set of boxes being moved
// Lower score = better destination
double eval_dest(const State& state, int dest, int current_target, const std::vector<int>& block, int lookahead) {
    double score = 0.0;
    const auto& dstack = state.stacks[dest];

    if (dstack.empty()) {
        score -= 500.0; // empty stacks are great buffers
    } else {
        score += (double)dstack.size() * 0.5; // penalize tall stacks
    }

    // Penalty for covering soon-needed boxes already in dest
    for (int bv : dstack) {
        if (bv > current_target && bv < current_target + lookahead) {
            // This box is needed soon, and we're putting stuff on top of it
            int depth_penalty = (int)block.size(); // how much we're adding on top
            score += 5.0 * depth_penalty;
        }
    }

    // Penalty for burying soon-needed boxes within the block itself
    for (int i = 0; i < (int)block.size(); i++) {
        int bv = block[i];
        if (bv > current_target && bv < current_target + lookahead) {
            // This box is needed soon, and it'll be buried under (block.size()-1-i) boxes
            int boxes_above = (int)block.size() - 1 - i;
            score += 4.0 * (boxes_above + (int)dstack.size() > 0 ? 0 : 0);
            // Actually the penalty is that to get bv later, we need to move everything above it
            score += 3.0 * boxes_above;
        }
    }

    return score;
}

// Find best destination for a block of boxes
int best_dest(const State& state, int src_stack, int current_target, const std::vector<int>& block, int lookahead) {
    double best_score = 1e18;
    int best_d = -1;
    for (int d = 0; d < state.M; d++) {
        if (d == src_stack) continue;
        double s = eval_dest(state, d, current_target, block, lookahead);
        if (s < best_score) {
            best_score = s;
            best_d = d;
        }
    }
    return best_d;
}

// Run the greedy solution with strategic splitting
// split_window: how many future targets to consider for splitting
// Returns the total energy
long long run_greedy_split(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           int split_window, int lookahead,
                           std::vector<std::pair<int,int>>& out_ops, bool record_ops) {
    State state(N, M, init_stacks);
    if (!record_ops) state.ops.clear();

    const int OP_LIMIT = 4900; // leave some margin

    for (int target = 0; target < N; target++) {
        if (state.is_on_top(target)) {
            state.carry_out(target);
            // Chain: carry out consecutive targets that are now on top
            while (target + 1 < N && state.is_on_top(target + 1)) {
                target++;
                state.carry_out(target);
            }
            continue;
        }

        int src = state.box_pos[target].first;
        int h_target = state.box_pos[target].second;
        int block_size = (int)state.stacks[src].size() - h_target - 1;

        if (block_size <= 0) {
            // target is on top (shouldn't reach here due to is_on_top check above)
            state.carry_out(target);
            while (target + 1 < N && state.is_on_top(target + 1)) {
                target++;
                state.carry_out(target);
            }
            continue;
        }

        // Get block above target (bottom to top within block)
        std::vector<int> above = state.get_above(target);

        // Find soon-needed boxes in the block above target
        // "Soon-needed" = within next split_window targets
        int best_priority_idx = -1; // index in 'above' array
        int best_priority_val = N;  // the box value
        for (int i = 0; i < (int)above.size(); i++) {
            int bv = above[i];
            if (bv > target && bv < target + split_window && bv < best_priority_val) {
                best_priority_val = bv;
                best_priority_idx = i;
            }
        }

        bool do_split = false;
        // Only split if:
        // 1. There's a priority box that's NOT at the top (would be buried)
        // 2. We have operation budget
        // 3. The block is big enough that splitting saves energy
        if (best_priority_idx >= 0 && best_priority_idx < (int)above.size() - 1
            && state.ops_count + 10 < OP_LIMIT && block_size >= 3) {
            // Priority box is buried under (above.size() - 1 - best_priority_idx) boxes
            int boxes_above_priority = (int)above.size() - 1 - best_priority_idx;
            // Splitting saves roughly: boxes_above_priority - 1 energy (vs not splitting)
            // Cost of extra move: 2 (to move priority box alone)
            // Net savings: boxes_above_priority - 1 - 2 + (boxes_above_priority + 1) = ...
            // Actually: without split: total future cost to re-expose priority = boxes_above_priority + 1
            // With split: extra cost now = 2 (move priority to empty stack)
            // So net savings = boxes_above_priority + 1 - 2 = boxes_above_priority - 1
            if (boxes_above_priority >= 2) {
                do_split = true;
            }
        }

        if (do_split) {
            // Strategy: Move boxes above priority target to dest1, move priority target to dest2,
            // then move remaining (between target and priority) to dest3, expose target

            int priority_val = best_priority_val;
            int src_stack = state.box_pos[target].first;

            // Step 1: Move everything above priority_val to a good destination
            int priority_h = state.box_pos[priority_val].second;
            int above_priority_count = (int)state.stacks[src_stack].size() - priority_h - 1;

            if (above_priority_count > 0) {
                int top_box = state.stacks[src_stack][priority_h + 1];
                std::vector<int> top_block(state.stacks[src_stack].begin() + priority_h + 1,
                                          state.stacks[src_stack].end());
                int d1 = best_dest(state, src_stack, target, top_block, lookahead);
                state.move(top_box, d1);
            }

            // Step 2: Move priority_val to a good spot (preferably empty stack or short stack)
            // After step 1, priority_val is on top of [... target ... stuff ... priority_val]
            // Find best destination for priority_val alone
            src_stack = state.box_pos[priority_val].first; // might have changed? no, we only moved stuff above it
            int between_count = state.box_pos[priority_val].second - state.box_pos[target].second - 1;

            if (between_count > 0) {
                // There are boxes between target and priority_val
                // Move priority_val + nothing above it (since we moved top stuff) to a good empty stack
                std::vector<int> pblock = {priority_val};
                int d2 = -1;
                // Prefer empty stacks
                for (int d = 0; d < M; d++) {
                    if (d == src_stack) continue;
                    if (state.stacks[d].empty()) { d2 = d; break; }
                }
                if (d2 < 0) {
                    d2 = best_dest(state, src_stack, target, pblock, lookahead);
                }
                state.move(priority_val, d2);

                // Step 3: Move remaining boxes between target and (where priority was)
                // Now they're the block above target
                std::vector<int> remaining = state.get_above(target);
                if (!remaining.empty()) {
                    int first_remaining = remaining[0];
                    int d3 = best_dest(state, state.box_pos[target].first, target, remaining, lookahead);
                    state.move(first_remaining, d3);
                }
            } else {
                // Priority is directly above target (between_count == 0)
                // Move priority_val to a good spot, then target is exposed
                std::vector<int> pblock = {priority_val};
                int d2 = -1;
                for (int d = 0; d < M; d++) {
                    if (d == src_stack) continue;
                    if (state.stacks[d].empty()) { d2 = d; break; }
                }
                if (d2 < 0) {
                    d2 = best_dest(state, src_stack, target, pblock, lookahead);
                }
                state.move(priority_val, d2);
            }

            // Now target should be on top
            state.carry_out(target);

            // Chain carries
            while (target + 1 < N && state.is_on_top(target + 1)) {
                target++;
                state.carry_out(target);
            }
        } else {
            // Simple single move: move entire block above target to best destination
            int first_above = state.stacks[src][h_target + 1];
            int d = best_dest(state, src, target, above, lookahead);
            state.move(first_above, d);
            state.carry_out(target);

            // Chain carries
            while (target + 1 < N && state.is_on_top(target + 1)) {
                target++;
                state.carry_out(target);
            }
        }
    }

    if (record_ops) out_ops = std::move(state.ops);
    return state.energy;
}

// SA-optimized version: parameterize destination choices and optimize them
// Plan representation: for each target, store destination choices
// But since splitting changes the structure, we'll do SA over heuristic parameters

struct GreedyParams {
    int split_window;
    int lookahead;
    double empty_bonus;
    double height_penalty;
    double cover_penalty;
    double bury_penalty;
};

// Parameterized greedy with configurable heuristics
long long run_parameterized_greedy(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                                    const GreedyParams& params,
                                    std::vector<std::pair<int,int>>& out_ops, bool record_ops) {
    State state(N, M, init_stacks);
    if (!record_ops) state.ops.clear();

    const int OP_LIMIT = 4900;

    auto eval_dest_param = [&](int dest, int src_stack, int current_target,
                               const std::vector<int>& block) -> double {
        double score = 0.0;
        const auto& dstack = state.stacks[dest];

        if (dstack.empty()) {
            score -= params.empty_bonus;
        } else {
            score += (double)dstack.size() * params.height_penalty;
        }

        for (int bv : dstack) {
            if (bv > current_target && bv < current_target + params.lookahead) {
                score += params.cover_penalty * (double)block.size();
            }
        }

        for (int i = 0; i < (int)block.size(); i++) {
            int bv = block[i];
            if (bv > current_target && bv < current_target + params.lookahead) {
                int boxes_above = (int)block.size() - 1 - i;
                score += params.bury_penalty * boxes_above;
            }
        }

        return score;
    };

    auto find_best_dest_param = [&](int src_stack, int current_target,
                                    const std::vector<int>& block) -> int {
        double best_score = 1e18;
        int best_d = -1;
        for (int d = 0; d < M; d++) {
            if (d == src_stack) continue;
            double s = eval_dest_param(d, src_stack, current_target, block);
            if (s < best_score) {
                best_score = s;
                best_d = d;
            }
        }
        return best_d;
    };

    for (int target = 0; target < N; target++) {
        if (state.is_on_top(target)) {
            state.carry_out(target);
            while (target + 1 < N && state.is_on_top(target + 1)) {
                target++;
                state.carry_out(target);
            }
            continue;
        }

        int src = state.box_pos[target].first;
        int h_target = state.box_pos[target].second;
        int block_size = (int)state.stacks[src].size() - h_target - 1;

        std::vector<int> above = state.get_above(target);

        // Find best priority box for splitting
        int best_priority_idx = -1;
        int best_priority_val = N;
        for (int i = 0; i < (int)above.size(); i++) {
            int bv = above[i];
            if (bv > target && bv < target + params.split_window && bv < best_priority_val) {
                best_priority_val = bv;
                best_priority_idx = i;
            }
        }

        bool do_split = false;
        if (best_priority_idx >= 0 && best_priority_idx < (int)above.size() - 1
            && state.ops_count + 10 < OP_LIMIT && block_size >= 3) {
            int boxes_above_priority = (int)above.size() - 1 - best_priority_idx;
            if (boxes_above_priority >= 2) {
                do_split = true;
            }
        }

        if (do_split) {
            int priority_val = best_priority_val;
            int src_stack = state.box_pos[target].first;

            int priority_h = state.box_pos[priority_val].second;
            int above_priority_count = (int)state.stacks[src_stack].size() - priority_h - 1;

            if (above_priority_count > 0) {
                int top_box = state.stacks[src_stack][priority_h + 1];
                std::vector<int> top_block(state.stacks[src_stack].begin() + priority_h + 1,
                                          state.stacks[src_stack].end());
                int d1 = find_best_dest_param(src_stack, target, top_block);
                state.move(top_box, d1);
            }

            src_stack = state.box_pos[priority_val].first;
            int between_count = state.box_pos[priority_val].second - state.box_pos[target].second - 1;

            if (between_count > 0) {
                std::vector<int> pblock = {priority_val};
                int d2 = -1;
                for (int d = 0; d < M; d++) {
                    if (d == src_stack) continue;
                    if (state.stacks[d].empty()) { d2 = d; break; }
                }
