int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> init_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N / M; j++)
            std::cin >> init_stacks[i][j];

    // Try multiple parameter configurations and pick the best
    GreedyParams best_params;
    long long best_energy = 1e18;
    std::vector<std::pair<int,int>> best_ops;

    // Base configurations to try
    struct ParamSet {
        int split_window;
        int lookahead;
        double empty_bonus;
        double height_penalty;
        double cover_penalty;
        double bury_penalty;
    };

    std::vector<ParamSet> configs = {
        {5, 8, 500.0, 0.5, 5.0, 3.0},
        {3, 5, 400.0, 0.3, 4.0, 2.5},
        {8, 12, 600.0, 0.8, 6.0, 4.0},
        {4, 6, 450.0, 0.4, 4.5, 3.5},
        {6, 10, 550.0, 0.6, 5.5, 3.0},
        {10, 15, 700.0, 1.0, 7.0, 4.5},
        {2, 4, 300.0, 0.2, 3.0, 2.0},
        {7, 10, 500.0, 0.7, 5.0, 3.5},
    };

    for (auto& cfg : configs) {
        if (elapsed() > 0.3) break;
        GreedyParams p;
        p.split_window = cfg.split_window;
        p.lookahead = cfg.lookahead;
        p.empty_bonus = cfg.empty_bonus;
        p.height_penalty = cfg.height_penalty;
        p.cover_penalty = cfg.cover_penalty;
        p.bury_penalty = cfg.bury_penalty;

        std::vector<std::pair<int,int>> ops;
        long long e = run_parameterized_greedy(init_stacks, N, M, p, ops, true);
        if (e < best_energy) {
            best_energy = e;
            best_params = p;
            best_ops = std::move(ops);
        }
    }

    // SA over parameters to find better configuration
    GreedyParams current_params = best_params;
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.1;
    double sa_start = elapsed();
    double sa_budget = TIME_LIMIT_SECONDS - 0.05 - sa_start;

    if (sa_budget > 0.1) {
        int iter = 0;
        while (true) {
            double now = elapsed();
            if (now >= TIME_LIMIT_SECONDS - 0.05) break;

            double progress = (now - sa_start) / sa_budget;
            progress = std::min(1.0, std::max(0.0, progress));
            double T = T_init * std::pow(T_final / T_init, progress);

            GreedyParams new_params = current_params;

            // Perturb one or two parameters
            int which = RGen.an_int(0, 5);
            switch (which) {
                case 0: new_params.split_window = std::max(1, std::min(20, new_params.split_window + RGen.an_int(-2, 2))); break;
                case 1: new_params.lookahead = std::max(2, std::min(30, new_params.lookahead + RGen.an_int(-3, 3))); break;
                case 2: new_params.empty_bonus = std::max(50.0, std::min(2000.0, new_params.empty_bonus + RGen.a_double(-100.0, 100.0))); break;
                case 3: new_params.height_penalty = std::max(0.01, std::min(5.0, new_params.height_penalty + RGen.a_double(-0.3, 0.3))); break;
                case 4: new_params.cover_penalty = std::max(0.5, std::min(20.0, new_params.cover_penalty + RGen.a_double(-1.5, 1.5))); break;
                case 5: new_params.bury_penalty = std::max(0.5, std::min(15.0, new_params.bury_penalty + RGen.a_double(-1.0, 1.0))); break;
            }

            std::vector<std::pair<int,int>> ops;
            long long e = run_parameterized_greedy(init_stacks, N, M, new_params, ops, true);

            if (e < current_energy) {
                current_energy = e;
                current_params = new_params;
                if (e < best_energy) {
                    best_energy = e;
                    best_params = new_params;
                    best_ops = std::move(ops);
                }
            } else {
                double delta = (double)(e - current_energy);
                if (T > 1e-9 && RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
                    current_energy = e;
                    current_params = new_params;
                }
            }
            iter++;
        }
    }

    // Output best solution
    for (auto& op : best_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}
