                       std::vector<std::pair<int,int>>* out_ops) {
    State state(N, M, init_stacks);
    const int OP_LIMIT = 4950;

    auto fbest = [&](int src, int target, int bh, int bs) -> int {
        return find_best_dest(state, src, target, bh, bs, p.lookahead,
                            p.empty_bonus, p.height_pen, p.cover_pen, p.bury_pen);
    };

    if (out_ops) {
        out_ops->clear();
        out_ops->reserve(N * 3);
    }

    for (int target = 0; target < N; target++) {
        if (state.is_on_top(target)) {
            if (out_ops) out_ops->push_back({target + 1, 0});
            state.carry_out(target);
            while (target + 1 < N && state.is_on_top(target + 1)) {
                target++;
                if (out_ops) out_ops->push_back({target + 1, 0});
                state.carry_out(target);
            }
            continue;
        }

        int src = state.box_pos[target].first;
        int h_target = state.box_pos[target].second;
        int above_count = (int)state.stacks[src].size() - h_target - 1;

        // Check for splitting opportunity
        bool did_split = false;
        if (above_count >= 3 && state.ops_count + 10 < OP_LIMIT) {
            // Find soonest-needed box in the block above target
            int best_pri_h = -1;
            int best_pri_val = N;
            for (int i = h_target + 1; i < (int)state.stacks[src].size(); i++) {
                int bv = state.stacks[src][i];
                if (bv > target && bv < target + p.split_window && bv < best_pri_val) {
                    best_pri_val = bv;
                    best_pri_h = i;
                }
            }

            if (best_pri_h >= 0) {
                int boxes_above_pri = (int)state.stacks[src].size() - best_pri_h - 1;
                if (boxes_above_pri >= p.split_threshold) {
                    did_split = true;

                    // Step 1: Move everything above priority to a destination
                    if (boxes_above_pri > 0) {
                        int top_box = state.stacks[src][best_pri_h + 1];
                        int d1 = fbest(src, target, best_pri_h + 1, boxes_above_pri);
                        if (out_ops) out_ops->push_back({top_box + 1, d1 + 1});
                        state.move(top_box, d1);
                    }

                    // Step 2: Move priority box (now on top or above some boxes) to good spot
                    src = state.box_pos[target].first;
                    int pri_h_now = state.box_pos[best_pri_val].second;
                    int between = pri_h_now - state.box_pos[target].second - 1;

                    if (between > 0) {
                        // Priority is above target with stuff between
                        // Move priority (alone since stuff above was moved) to empty/good spot
                        int d2 = -1;
                        int pri_src = state.box_pos[best_pri_val].first;
                        for (int d = 0; d < M; d++) {
                            if (d == pri_src) continue;
                            if (state.stacks[d].empty()) { d2 = d; break; }
                        }
                        if (d2 < 0) {
                            d2 = fbest(pri_src, target, pri_h_now, 1);
                        }
                        if (out_ops) out_ops->push_back({best_pri_val + 1, d2 + 1});
                        state.move(best_pri_val, d2);

                        // Step 3: Move remaining (between target and where priority was)
                        src = state.box_pos[target].first;
                        h_target = state.box_pos[target].second;
                        int remaining = (int)state.stacks[src].size() - h_target - 1;
                        if (remaining > 0) {
                            int first_rem = state.stacks[src][h_target + 1];
                            int d3 = fbest(src, target, h_target + 1, remaining);
                            if (out_ops) out_ops->push_back({first_rem + 1, d3 + 1});
                            state.move(first_rem, d3);
                        }
                    } else {
                        // Priority is directly above target (or is the only box)
                        // Just move it somewhere good
                        int pri_src = state.box_pos[best_pri_val].first;
                        int d2 = -1;
                        for (int d = 0; d < M; d++) {
                            if (d == pri_src) continue;
                            if (state.stacks[d].empty()) { d2 = d; break; }
                        }
                        if (d2 < 0) {
                            d2 = fbest(pri_src, target, state.box_pos[best_pri_val].second, 1);
                        }
                        if (out_ops) out_ops->push_back({best_pri_val + 1, d2 + 1});
                        state.move(best_pri_val, d2);
                    }
                }
            }
        }

        if (!did_split) {
            // Simple: move all above target to best dest
            src = state.box_pos[target].first;
            h_target = state.box_pos[target].second;
            above_count = (int)state.stacks[src].size() - h_target - 1;
            if (above_count > 0) {
                int first_above = state.stacks[src][h_target + 1];
                int d = fbest(src, target, h_target + 1, above_count);
                if (out_ops) out_ops->push_back({first_above + 1, d + 1});
                state.move(first_above, d);
            }
        }

        if (out_ops) out_ops->push_back({target + 1, 0});
        state.carry_out(target);

        while (target + 1 < N && state.is_on_top(target + 1)) {
            target++;
            if (out_ops) out_ops->push_back({target + 1, 0});
            state.carry_out(target);
        }
    }

    if (out_ops && (int)out_ops->size() > 5000) {
        // Fallback: run without splitting if too many ops
        SolveParams p2 = p;
        p2.split_threshold = 999; // disable splitting
        return solve_greedy(init_stacks, N, M, p2, out_ops);
    }

    return state.energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> init_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N / M; j++)
            std::cin >> init_stacks[i][j];

    // Parameter configurations to try
    struct PC { int sw; int la; double eb; double hp; double cp; double bp; int st; };
    std::vector<PC> configs = {
        {5, 8, 500.0, 0.5, 5.0, 3.0, 2},
        {3, 5, 400.0, 0.3, 4.0, 2.5, 2},
        {8, 12, 600.0, 0.8, 6.0, 4.0, 2},
        {4, 6, 450.0, 0.4, 4.5, 3.5, 2},
        {6, 10, 550.0, 0.6, 5.5, 3.0, 2},
        {10, 15, 700.0, 1.0, 7.0, 4.5, 2},
        {5, 8, 500.0, 0.5, 5.0, 3.0, 3},
        {4, 8, 600.0, 0.5, 6.0, 3.5, 2},
        {5, 10, 450.0, 0.6, 5.0, 4.0, 2},
        {6, 8, 500.0, 0.4, 4.0, 3.0, 3},
        {3, 6, 550.0, 0.5, 5.5, 2.5, 2},
        {7, 10, 500.0, 0.7, 5.0, 3.5, 2},
        // No splitting variants
        {5, 8, 500.0, 0.5, 5.0, 3.0, 999},
        {4, 6, 450.0, 0.4, 4.5, 3.5, 999},
        {8, 12, 600.0, 0.8, 6.0, 4.0, 999},
        {6, 10, 550.0, 0.6, 5.5, 3.0, 999},
    };

    long long best_energy = 1e18;
    SolveParams best_params;
    std::vector<std::pair<int,int>> best_ops;

    for (auto& c : configs) {
        if (elapsed() > 0.4) break;
        SolveParams sp{c.sw, c.la, c.eb, c.hp, c.cp, c.bp, c.st};
        std::vector<std::pair<int,int>> ops;
        long long e = solve_greedy(init_stacks, N, M, sp, &ops);
        if (e < best_energy && (int)ops.size() <= 5000) {
            best_energy = e;
            best_params = sp;
            best_ops = std::move(ops);
        }
    }

    // SA over parameters
    SolveParams current_params = best_params;
    long long current_energy = best_energy;
    double T_init = 25.0;
    double T_final = 0.05;
    double sa_start = elapsed();
    double sa_budget = TIME_LIMIT_SECONDS - 0.05 - sa_start;

    if (sa_budget > 0.05) {
        int no_improve = 0;
        while (true) {
            double now = elapsed();
            if (now >= TIME_LIMIT_SECONDS - 0.05) break;
            double progress = std::min(1.0, std::max(0.0, (now - sa_start) / sa_budget));
            double T = T_init * std::pow(T_final / T_init, progress);

            if (no_improve > 40) {
                current_params = best_params;
                current_energy = best_energy;
                no_improve = 0;
            }

            SolveParams new_params = current_params;
            int num_perturb = (RGen.a_double(0, 1) < 0.25) ? 2 : 1;
            for (int pp = 0; pp < num_perturb; pp++) {
                int which = RGen.an_int(0, 6);
                switch (which) {
                    case 0: new_params.split_window = std::max(1, std::min(20, new_params.split_window + RGen.an_int(-2, 2))); break;
                    case 1: new_params.lookahead = std::max(2, std::min(30, new_params.lookahead + RGen.an_int(-3, 3))); break;
                    case 2: new_params.empty_bonus = std::max(50.0, std::min(2000.0, new_params.empty_bonus + RGen.a_double(-80.0, 80.0))); break;
                    case 3: new_params.height_pen = std::max(0.01, std::min(5.0, new_params.height_pen + RGen.a_double(-0.2, 0.2))); break;
                    case 4: new_params.cover_pen = std::max(0.5, std::min(20.0, new_params.cover_pen + RGen.a_double(-1.0, 1.0))); break;
                    case 5: new_params.bury_pen = std::max(0.5, std::min(15.0, new_params.bury_pen + RGen.a_double(-0.8, 0.8))); break;
                    case 6: new_params.split_threshold = std::max(1, std::min(10, new_params.split_threshold + RGen.an_int(-1, 1))); break;
                }
            }

            std::vector<std::pair<int,int>> ops;
            long long e = solve_greedy(init_stacks, N, M, new_params, &ops);

            if ((int)ops.size() > 5000) continue;

            if (e < current_energy) {
                current_energy = e;
                current_params = new_params;
                no_improve = 0;
                if (e < best_energy) {
                    best_energy = e;
                    best_params = new_params;
                    best_ops = std::move(ops);
                }
            } else {
                no_improve++;
                double delta = (double)(e - current_energy);
                if (T > 1e-9 && RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
                    current_energy = e;
                    current_params = new_params;
                }
            }
        }
    }

    for (auto& op : best_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}
